## 4.4 PM Scheduler (Tactical)

### 4.4.1 Purpose

Schedule preventive maintenance for the 12-week tactical horizon, respecting track availability, labor capacity, and material constraints.

### 4.4.2 Implementation

```typescript
interface TacticalSchedulerConfig {
  horizonWeeks: number;           // 12
  materialCheckDaysHard: number;  // 14 (hard constraint)
  materialCheckDaysSoft: number;  // 90 (soft constraint)
  trackUtilizationTarget: number; // 0.85
}

class TacticalPMScheduler {
  async schedule(depotId: string): Promise<SchedulingResult> {
    const config = this.config;
    const horizonEnd = addWeeks(new Date(), config.horizonWeeks);

    // 1. Get pending PMs that need scheduling
    const pendingPMs = await this.getPendingPMs(depotId, horizonEnd);

    // 2. Get resource availability
    const trackAvailability = await this.getTrackAvailability(depotId, horizonEnd);
    const laborCapacity = await this.getLaborCapacity(depotId, horizonEnd);
    const materialPositions = await this.getMaterialPositions(depotId);

    // 3. Sort PMs by priority (urgency, criticality)
    const sortedPMs = this.prioritizePMs(pendingPMs);

    // 4. Schedule each PM
    const scheduled: ScheduledPM[] = [];
    const deferred: DeferredPM[] = [];
    const materialWarnings: MaterialWarning[] = [];

    for (const pm of sortedPMs) {
      const result = await this.scheduleSinglePM(
        pm,
        trackAvailability,
        laborCapacity,
        materialPositions,
        scheduled
      );

      if (result.scheduled) {
        scheduled.push(result.scheduled);

        // Reserve materials
        await this.reserveMaterials(result.scheduled, materialPositions);

        // Update availability
        this.updateAvailability(
          result.scheduled,
          trackAvailability,
          laborCapacity
        );
      } else {
        deferred.push({
          pm,
          reason: result.reason,
          suggestedDate: result.suggestedDate
        });
      }
